CREATE TABLE `station` (
  `sn` int NOT NULL AUTO_INCREMENT COMMENT 'sn',
  `stationID` char(6) NOT NULL COMMENT '站碼',
  `stationCode` char(6) DEFAULT NULL COMMENT '流水碼',
  `stationName` char(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '中文站名',
  `stationNameEN` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '英文站名',
  `altitude` float DEFAULT NULL COMMENT '高度',
  `longitude` decimal(10,6) DEFAULT NULL COMMENT 'WGS84十分位經度座標',
  `latitude` decimal(9,6) DEFAULT NULL COMMENT 'WGS84十分位緯度座標',
  `longitudeWGS84DMS` char(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'WGS84度分秒經度',
  `latitudeWGS84DMS` char(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'WGS84度分秒緯度',
  `longitudeTWD67` decimal(10,6) DEFAULT NULL,
  `latitudeTWD67` decimal(10,6) DEFAULT NULL,
  `longitudeTWD67DMS` char(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'TWD67度分秒經度',
  `latitudeTWD67DMS` char(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'TWD67度分秒緯度',
  `xTM2` decimal(9,2) DEFAULT NULL COMMENT '二度分帶X座標',
  `yTM2` decimal(10,2) DEFAULT NULL COMMENT '二度分帶Y座標',
  `countryName` char(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '城市',
  `townName` char(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '鄉鎮名稱',
  `address` varchar(80) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '地址',
  `areaCode` smallint DEFAULT NULL COMMENT '區域代碼',
  `area` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '區域名稱',
  `flow` char(14) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '自動雨量站所屬河川流域',
  `stationAttribute` char(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '氣象站屬性(如局屬站，雨量站，農業站)',
  `obsFrequency` char(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '觀測頻率跟次數',
  `stationStartDate` date DEFAULT NULL COMMENT '設站日期',
  `stationEndDate` date DEFAULT NULL COMMENT '撤站日期',
  `stationPauseDate` date DEFAULT NULL COMMENT '最新預定施工日期',
  `dataStartDate` date DEFAULT NULL COMMENT '資料開始日期',
  `dataEndDate` date DEFAULT NULL COMMENT '最新資料日期',
  `switch` char(1) NOT NULL DEFAULT '0' COMMENT '測站開關 0 on/1off',
  `flag` char(1) NOT NULL DEFAULT '2' COMMENT '"資料供應等級標章 \\n1可認證販售/2僅可公布不認證販售/3不可對外公布"',
  `chargeIns` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '所屬機關',
  `chargeInsDescription` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '詳細主管機關資料',
  `remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '備註',
  `webRemark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT '網頁顯示備註',
  `stno5` char(5) DEFAULT NULL COMMENT '五碼站碼',
  `sightDescrption` text COMMENT '當地環境紀錄文字log',
  `migrateDescrption` text COMMENT '測站搬遷紀錄文字log',
  `maintainDescrption` text COMMENT '維護紀錄文字log',
  `stationIDBefore` char(6) DEFAULT NULL COMMENT '舊站碼',
  `stationIDAfter` char(6) DEFAULT NULL COMMENT '新站碼',
  `itemClass` char(6) DEFAULT NULL COMMENT '測站特有的資訊類別(如儀器，如觀測項目)',
  `lastUpdateTime` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '實際異動時間',
  `RespStn` char(10) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '責任區',
  `HBarometer` char(10) DEFAULT NULL COMMENT '氣壓計海面上高度',
  `HTherm` char(10) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '溫度計地面高度',
  `HRaingauge` char(10) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '雨量器口面地上高度',
  `HAnem` char(10) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '風速儀地上高度',
  `obs_station_flag` char(1) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '觀測資料使用狀況 0:正常 1:目前觀測資料不使用',
  `qc_group_id` int DEFAULT NULL,
  PRIMARY KEY (`sn`),
  UNIQUE KEY `stationID_UNIQUE` (`stationID`),
  KEY `qc_group_id` (`qc_group_id`),
  CONSTRAINT `station_ibfk_1` FOREIGN KEY (`qc_group_id`) REFERENCES `qc_group` (`sn`)
) ENGINE=InnoDB AUTO_INCREMENT=30709 DEFAULT CHARSET=latin1;
